/* Parsed icon caches (filled on first use) */
static uint8_t _nav16[256], _nav32[1024];
static uint8_t _term16[256], _term32[1024];
static uint8_t _desk16[256], _desk32[1024];
static uint8_t _vol16[256];
static bool _icons_parsed = false;

static void _parse_icons(void) {
    if (_icons_parsed) return;
    _icons_parsed = true;
    /* Best-effort: if parsing fails the arrays stay zeroed */
    ico_parse_16(ico_navigator, sizeof(ico_navigator), _nav16);
    ico_parse_32(ico_navigator, sizeof(ico_navigator), _nav32);
    ico_parse_16(ico_terminal,  sizeof(ico_terminal),  _term16);
    ico_parse_32(ico_terminal,  sizeof(ico_terminal),  _term32);
    ico_parse_16(ico_desktop,   sizeof(ico_desktop),   _desk16);
    ico_parse_32(ico_desktop,   sizeof(ico_desktop),   _desk32);
    ico_parse_16(ico_volume,    sizeof(ico_volume),    _vol16);
}

const uint8_t *fn_icon16_navigator_get(void) { _parse_icons(); return _nav16; }
const uint8_t *fn_icon32_navigator_get(void) { _parse_icons(); return _nav32; }
const uint8_t *fn_icon16_terminal_get(void)  { _parse_icons(); return _term16; }
const uint8_t *fn_icon32_terminal_get(void)  { _parse_icons(); return _term32; }
const uint8_t *fn_icon16_desktop_get(void)   { _parse_icons(); return _desk16; }
const uint8_t *fn_icon32_desktop_get(void)   { _parse_icons(); return _desk32; }
const uint8_t *fn_icon16_volume_get(void)    { _parse_icons(); return _vol16; }

